import { Component, Event, EventEmitter, h, Prop, State } from '@stencil/core';
import { KEYBOARD_KEYS } from '../../../models/keycodes.model';

@Component({
  tag: 'wdpr-media-player-control-progress-bar',
  shadow: true,
})
export class WdprMediaPlayerControlProgressBar {
  private _barEl?: HTMLElement;
  private _rafPending = false;
  private _pendingTime: number | null = null;

  @State() _dragging = false;

  @Prop() currentTime = 0;
  @Prop() duration = 0;

  @Event({ bubbles: true, composed: true }) wdprBarTimeChange!: EventEmitter<{ time: number }>;
  private _clamp(n: number, min: number, max: number) {
    return Math.min(max, Math.max(min, n));
  }

  private _getTimeFromClientX(clientX: number) {
    if (!this.duration || !this._barEl) return 0;
    const rect = this._barEl.getBoundingClientRect();
    const percent = this._clamp((clientX - rect.left) / rect.width, 0, 1);

    return percent * this.duration;
  }

  private _emitSeekThrottled(time: number) {
    this._pendingTime = time;

    if (this._rafPending) return;
    this._rafPending = true;

    requestAnimationFrame(() => {
      this._rafPending = false;
      if (this._pendingTime == null) return;
      this.wdprBarTimeChange.emit({ time: this._pendingTime });
      this._pendingTime = null;
    });
  }

  private _onPointerDown = (ev: PointerEvent) => {
    if (!this.duration || !this._barEl) return;

    if (ev.pointerType === 'mouse' && ev.button !== 0) return;

    this._dragging = true;

    (ev.currentTarget as HTMLElement).setPointerCapture?.(ev.pointerId);

    const time = this._getTimeFromClientX(ev.clientX);
    this.wdprBarTimeChange.emit({ time });
  };

  private _onPointerMove = (ev: PointerEvent) => {
    if (!this._dragging || !this.duration) return;

    const time = this._getTimeFromClientX(ev.clientX);
    this._emitSeekThrottled(time);
  };

  private _onPointerUp = (ev: PointerEvent) => {
    if (!this._dragging) return;
    this._dragging = false;

    if (this.duration) {
      const time = this._getTimeFromClientX(ev.clientX);
      this.wdprBarTimeChange.emit({ time });
    }

    (ev.currentTarget as HTMLElement).releasePointerCapture?.(ev.pointerId);
  };

  private _onPointerCancel = (ev: PointerEvent) => {
    if (!this._dragging) return;
    this._dragging = false;
    (ev.currentTarget as HTMLElement).releasePointerCapture?.(ev.pointerId);
  };

  private _onKeyDown = (ev: KeyboardEvent) => {
    if (!this.duration) return;

    const step = Math.max(1, Math.round(this.duration * 0.05));
    let next = this.currentTime;

    switch (ev.key) {
      case KEYBOARD_KEYS.ARROW_LEFT:
      case KEYBOARD_KEYS.ARROW_DOWN:
        next = this.currentTime - step;
        ev.preventDefault();
        break;
      case KEYBOARD_KEYS.ARROW_RIGHT:
      case KEYBOARD_KEYS.ARROW_UP:
        next = this.currentTime + step;
        ev.preventDefault();
        break;
      case KEYBOARD_KEYS.HOME:
        next = 0;
        ev.preventDefault();
        break;
      case KEYBOARD_KEYS.END:
        next = this.duration;
        ev.preventDefault();
        break;
      default:
        return;
    }

    this.wdprBarTimeChange.emit({ time: this._clamp(next, 0, this.duration) });
  };

  render() {
    const percent = this.duration > 0 ? this._clamp((this.currentTime / this.duration) * 100, 0, 100) : 0;

    return (
      <div
        ref={el => (this._barEl = el as HTMLElement)}
        class="w-full rounded-full cursor-pointer select-none h-dimension-075 bg-surface-white-000-a48 touch-none"
        role="slider"
        aria-label="Seek"
        aria-valuemin="0"
        aria-valuemax={String(Math.max(0, this.duration))}
        aria-valuenow={String(Math.max(0, Math.min(this.currentTime, this.duration || 0)))}
        aria-valuetext={this.duration ? `${Math.round(this.currentTime)} of ${Math.round(this.duration)} seconds` : '0 seconds'}
        tabIndex={0}
        onPointerDown={this._onPointerDown}
        onPointerMove={this._onPointerMove}
        onPointerUp={this._onPointerUp}
        onPointerCancel={this._onPointerCancel}
        onKeyDown={this._onKeyDown}
      >
        <div class="h-full rounded-full bg-surface-default" style={{ width: `${percent}%` }} />
      </div>
    );
  }
}
